sql:
SELECT AVG(population) AS avg_african_population
FROM countries
WHERE continent = 'Africa' AND population > 100000000;

SELECT c.country_name, c.population, d.dataset_name
FROM countries c
CROSS JOIN datasets d;

external_knowledge:
- "particularly active" in this context refers to users with more than 10 contributions;
- "datasets and data sources" are contributions that users can make in the system;
- "combined total contribution" is the sum of the number of datasets and data sources a user has created.

sql:
SELECT AVG(population) 
FROM (
  SELECT population 
  FROM regions 
  WHERE population > (SELECT AVG(population) FROM regions)
) AS high_population_regions;

SELECT country_name, capital, (SELECT MAX(updated_at) FROM countries) AS last_updated_at 
FROM countries
WHERE population > 50000000;

SELECT d.dataset_name, dv.version_number, dv.version_notes
FROM datasets d
JOIN dataset_versions dv ON d.dataset_id = dv.dataset_id;

SELECT country_name, population 
FROM countries 
WHERE countrycode = '0' AND population > 1000000;

SELECT country_name 
FROM countries 
WHERE population > (SELECT AVG(population) FROM countries);

SELECT d.dataset_name, s.source_name
FROM datasets d
JOIN data_sources s ON d.data_source_id = s.source_id;

SELECT users.user_name, datasets.dataset_name
FROM datasets
INNER JOIN users ON datasets.created_by = users.user_id;
